SELECT grid_id
FROM grids
WHERE grid_type = 'DGGS' AND resolution > 5;

SELECT COUNT(*) AS active_grid_count
FROM grids
WHERE status = 'active';

SELECT grid_name
FROM grids
ORDER BY grid_name;

SELECT analysis_type
FROM grid_analysis_results
WHERE grid_id = 1;

SELECT COUNT(result_id) AS result_count
FROM grid_analysis_results
WHERE grid_id = 1;
